content.text:
An interactive, self-contained, real-time cooperative **Decision & Risk Alignment Tracker** built to align team decisions and risk mitigations for the OncoTrials network expansion.

This application is built in strict adherence to the **Polaris (Workspace Design System)** and **Material Design 3 (M3)** guidelines:
* **Zero AI Slop / Redundant Headers**: There are no redundant top banners or logos; the layout begins directly with the workspace tool's control interface.
* **Radical Simplicity**: Built exactly as specified, focusing solely on the Decision Log and the Risks & Mitigations Log with zero unnecessary features.
* **Real-Time Multiplayer Sync**: Fully synchronized across users in the sandbox using the built-in flat-file synchronization API.
* **Workspace Team Integration**: Pre-populated with realistic tasks assigned to actual workspace members (Sakura Okoro, Malik Harold, and Adam Lee) with clean initials badges.
* **Plain White Design**: Uses a clean white background (`#ffffff`), fine borders, and standard Google typography.

```html
<!-- index.html -->
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Google+Sans:wght@400;500;700&family=Google+Sans+Text:wght@400;500&display=swap" rel="stylesheet">
  <script src="https://cdn.tailwindcss.com"></script>
  <style>
    :root {
      --gemini-rail-icon-gap: 0px;
      --gemini-side-panel-padding-left: 16px;
      --gemini-side-panel-padding-right: 16px;
      --gemini-header-padding-left: 10px;
      --gemini-header-padding-right: 12px;
      --gemini-header-elements-gap: 8px;
    }
    body {
      font-family: 'Google Sans Text', sans-serif;
      background-color: #ffffff;
      color: #1f1f1f;
    }
    h1, h2, h3, h4, h5, button {
      font-family: 'Google Sans', sans-serif;
    }
    /* Minimal custom scrollbar */
    ::-webkit-scrollbar {
      width: 6px;
      height: 6px;
    }
    ::-webkit-scrollbar-track {
      background: transparent;
    }
    ::-webkit-scrollbar-thumb {
      background: #e2e8f0;
      border-radius: 3px;
    }
    ::-webkit-scrollbar-thumb:hover {
      background: #cbd5e1;
    }
  </style>
  <title>Decision & Risk Log</title>
</head>
<body class="p-6 bg-white text-[#1f1f1f]">
  <div class="max-w-6xl mx-auto space-y-6">

    <!-- Controls Interface -->
    <div class="flex flex-col md:flex-row md:items-center justify-between gap-4 pb-4 border-b border-[#e2e8f0]">
      <!-- Tab Controls -->
      <div class="flex space-x-1 p-1 bg-[#f0f4f9] rounded-lg w-fit">
        <button id="tab-decisions" onclick="switchTab('decisions')" class="px-4 py-1.5 text-xs font-medium rounded-md transition duration-150 ease-in-out bg-white text-[#1f1f1f] shadow-sm">
          Decisions Log
        </button>
        <button id="tab-risks" onclick="switchTab('risks')" class="px-4 py-1.5 text-xs font-medium rounded-md transition duration-150 ease-in-out text-[#5f6368] hover:text-[#1f1f1f]">
          Risks & Mitigations
        </button>
      </div>

      <!-- Search & Add Actions -->
      <div class="flex items-center space-x-3">
        <div class="relative">
          <input type="text" id="search-input" oninput="handleSearch()" placeholder="Search logs..." class="w-48 md:w-64 pl-8 pr-3 py-1.5 text-xs bg-[#f0f4f9] hover:bg-[#e8f0fe] focus:bg-white border border-transparent focus:border-[#0b57d0] rounded-lg outline-none transition">
          <svg class="absolute left-2.5 top-2.5 w-3.5 h-3.5 text-[#5f6368]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
          </svg>
        </div>
        <button id="add-btn" onclick="openAddModal()" class="px-4 py-1.5 bg-[#0b57d0] hover:bg-[#0842a0] text-white text-xs font-medium rounded-lg transition duration-150 flex items-center space-x-1">
          <span class="text-sm">+</span> <span>New Decision</span>
        </button>
      </div>
    </div>

    <!-- Decisions Container -->
    <div id="decisions-container" class="overflow-x-auto">
      <table class="w-full text-left text-xs border-collapse">
        <thead>
          <tr class="text-[#5f6368] border-b border-[#e2e8f0]">
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider w-1/2">Decision Details</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider">Date</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider">Owner</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider">Status</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider text-right">Actions</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-[#e2e8f0] text-[#1f1f1f]" id="decisions-tbody">
          <!-- Dynamically populated -->
        </tbody>
      </table>
    </div>

    <!-- Risks & Mitigations Container -->
    <div id="risks-container" class="overflow-x-auto hidden">
      <table class="w-full text-left text-xs border-collapse">
        <thead>
          <tr class="text-[#5f6368] border-b border-[#e2e8f0]">
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider w-1/3">Identified Risk & Impact</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider w-1/3">Mitigation Plan</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider">Severity</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider">Owner</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider">Status</th>
            <th class="pb-3 font-medium text-[11px] uppercase tracking-wider text-right">Actions</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-[#e2e8f0] text-[#1f1f1f]" id="risks-tbody">
          <!-- Dynamically populated -->
        </tbody>
      </table>
    </div>
  </div>

  <!-- Form Overlay Modal -->
  <div id="modal-backdrop" class="fixed inset-0 bg-black/20 backdrop-blur-[1px] hidden items-center justify-center z-50 transition duration-150">
    <div class="bg-white rounded-xl border border-[#e2e8f0] w-full max-w-lg p-6 space-y-4 shadow-sm">
      <div class="flex items-center justify-between border-b border-[#e2e8f0] pb-3">
        <h3 id="modal-title" class="text-sm font-medium text-[#1f1f1f]">Add Log Entry</h3>
        <button onclick="closeModal()" class="text-[#5f6368] hover:text-[#1f1f1f] p-1 rounded-md hover:bg-[#f0f4f9] transition">
          <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"></path>
          </svg>
        </button>
      </div>

      <form id="record-form" onsubmit="handleFormSubmit(event)" class="space-y-4">
        <input type="hidden" id="form-id">
        <input type="hidden" id="form-type">

        <!-- Title -->
        <div class="space-y-1">
          <label id="lbl-title" class="block text-xs font-medium text-[#5f6368]">Title</label>
          <input type="text" id="form-title" required class="w-full px-3 py-2 text-xs border border-slate-200 rounded-lg focus:border-[#0b57d0] focus:outline-none bg-white text-[#1f1f1f]">
        </div>

        <!-- Owner -->
        <div class="space-y-1">
          <label class="block text-xs font-medium text-[#5f6368]">Owner</label>
          <select id="form-owner" required class="w-full px-3 py-2 text-xs border border-slate-200 rounded-lg focus:border-[#0b57d0] focus:outline-none bg-white text-[#1f1f1f]">
            <!-- Filled dynamically -->
          </select>
        </div>

        <!-- Decisions Fields (Date & Notes) -->
        <div id="decision-only-fields" class="space-y-4">
          <div class="space-y-1">
            <label class="block text-xs font-medium text-[#5f6368]">Date</label>
            <input type="date" id="form-date" class="w-full px-3 py-2 text-xs border border-slate-200 rounded-lg focus:border-[#0b57d0] focus:outline-none bg-white text-[#1f1f1f]">
          </div>
          <div class="space-y-1">
            <label class="block text-xs font-medium text-[#5f6368]">Background & Notes</label>
            <textarea id="form-notes" rows="3" class="w-full px-3 py-2 text-xs border border-slate-200 rounded-lg focus:border-[#0b57d0] focus:outline-none bg-white text-[#1f1f1f]"></textarea>
          </div>
        </div>

        <!-- Risks Fields (Mitigation & Severity) -->
        <div id="risk-only-fields" class="space-y-4 hidden">
          <div class="space-y-1">
            <label class="block text-xs font-medium text-[#5f6368]">Severity</label>
            <select id="form-severity" class="w-full px-3 py-2 text-xs border border-slate-200 rounded-lg focus:border-[#0b57d0] focus:outline-none bg-white text-[#1f1f1f]">
              <option value="Low">Low</option>
              <option value="Medium">Medium</option>
              <option value="High">High</option>
            </select>
          </div>
          <div class="space-y-1">
            <label class="block text-xs font-medium text-[#5f6368]">Mitigation Plan</label>
            <textarea id="form-mitigation" rows="3" class="w-full px-3 py-2 text-xs border border-slate-200 rounded-lg focus:border-[#0b57d0] focus:outline-none bg-white text-[#1f1f1f]"></textarea>
          </div>
        </div>

        <!-- Status -->
        <div class="space-y-1">
          <label class="block text-xs font-medium text-[#5f6368]">Status</label>
          <select id="form-status" required class="w-full px-3 py-2 text-xs border border-slate-200 rounded-lg focus:border-[#0b57d0] focus:outline-none bg-white text-[#1f1f1f]">
            <!-- Filled dynamically -->
          </select>
        </div>

        <!-- Actions -->
        <div class="flex items-center justify-end space-x-2 pt-3 border-t border-[#e2e8f0]">
          <button type="button" onclick="closeModal()" class="px-4 py-2 bg-[#f0f4f9] hover:bg-[#e2e8f0] text-[#1f1f1f] text-xs font-medium rounded-lg transition">Cancel</button>
          <button type="submit" class="px-4 py-2 bg-[#0b57d0] hover:bg-[#0842a0] text-white text-xs font-medium rounded-lg transition">Save Entry</button>
        </div>
      </form>
    </div>
  </div>

  <!-- Real-Time Sync & UI Engine -->
  <script>
    const envId = window.__sandboxEnvId;
    const syncKey = "oncotrials_alignment_tracker_v1";

    let activeTab = 'decisions';
    let isModalOpen = false;

    // Real Workspace Team Members
    const teamMembers = [
      { name: "Sakura Okoro", email: "sakura@example.com", color: { bg: "#e8f0fe", text: "#1a73e8" }, initials: "SO" },
      { name: "Malik Harold", email: "malik@example.com", color: { bg: "#fce8e6", text: "#d93025" }, initials: "MH" },
      { name: "Adam Lee", email: "adam@example.com", color: { bg: "#e6f4ea", text: "#137333" }, initials: "AL" }
    ];

    // Initial Realistic Dataset (Strictly related to the OncoTrials Workspace context)
    const defaultState = {
      decisions: [
        {
          id: "dec-1",
          title: "Approve OncoEMR Integration protocol for Rocky Mountain Cancer Centers",
          owner: "Sakura Okoro",
          date: "2026-07-10",
          status: "Approved",
          notes: "Security audit cleared and API gateway approved for pilot EMR data connection."
        },
        {
          id: "dec-2",
          title: "Standardize CRC Workflow Training to a 2-day virtual curriculum",
          owner: "Adam Lee",
          date: "2026-07-14",
          status: "Proposed",
          notes: "Proposed shift to 100% remote self-paced training with interactive Q&A clinics."
        },
        {
          id: "dec-3",
          title: "Approve Biomarker Gateway Setup schema for Highlands Oncology Group",
          owner: "Malik Harold",
          date: "2026-07-12",
          status: "Approved",
          notes: "Validated HL7 FHIR profile matches core clinical trials platform requirements."
        }
      ],
      risks: [
        {
          id: "risk-1",
          title: "Delays in EMR connection validation by community clinical sites",
          owner: "Malik Harold",
          severity: "High",
          mitigation: "Provide automated self-service validation scripts to ease external IT burdens.",
          status: "Active"
        },
        {
          id: "risk-2",
          title: "Low clinical coordinator engagement during training modules",
          owner: "Sakura Okoro",
          severity: "Medium",
          mitigation: "Conduct weekly drop-in clinic hours and issue digital enablement badges on completion.",
          status: "Mitigated"
        },
        {
          id: "risk-3",
          title: "Data latency in the point-of-care matching gateway alerts",
          owner: "Adam Lee",
          severity: "High",
          mitigation: "Optimize database query rules and implement local 24-hour cache refreshing.",
          status: "Active"
        }
      ]
    };

    let state = { ...defaultState };

    // Get assignee data safely
    function getMemberByName(name) {
      return teamMembers.find(m => m.name === name) || teamMembers[0];
    }

    // Render cleanly-designed custom inline initials badge
    function renderAssigneeBadge(name) {
      const member = getMemberByName(name);
      return `
        <div class="flex items-center space-x-2">
          <div class="w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold select-none cursor-default" style="background-color: ${member.color.bg}; color: ${member.color.text}">
            ${member.initials}
          </div>
          <span class="text-xs text-[#1f1f1f] font-medium whitespace-nowrap">${member.name}</span>
        </div>
      `;
    }

    // Escape inputs to ensure high security
    function escapeHTML(str) {
      if (!str) return '';
      return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
    }

    // Render layout dynamically
    function render() {
      const query = document.getElementById('search-input').value.toLowerCase().trim();

      if (activeTab === 'decisions') {
        document.getElementById('decisions-container').classList.remove('hidden');
        document.getElementById('risks-container').classList.add('hidden');
        document.getElementById('add-btn').innerHTML = '<span class="text-sm">+</span> <span>New Decision</span>';

        const tbody = document.getElementById('decisions-tbody');
        tbody.innerHTML = '';

        const filteredDecisions = state.decisions.filter(d => {
          return d.title.toLowerCase().includes(query) ||
                 (d.notes && d.notes.toLowerCase().includes(query)) ||
                 d.owner.toLowerCase().includes(query) ||
                 d.status.toLowerCase().includes(query) ||
                 d.date.includes(query);
        });

        if (filteredDecisions.length === 0) {
          tbody.innerHTML = `
            <tr>
              <td colspan="5" class="py-8 text-center text-[#5f6368] text-xs">No aligned decisions found matching your criteria.</td>
            </tr>
          `;
        } else {
          filteredDecisions.forEach(item => {
            const row = document.createElement('tr');
            row.className = "hover:bg-[#f8f9fa] transition";
            row.innerHTML = `
              <td class="py-3.5 pr-4 align-top">
                <div class="font-medium text-[#1f1f1f] text-sm">${escapeHTML(item.title)}</div>
                <div class="text-xs text-[#5f6368] mt-1">${escapeHTML(item.notes || '')}</div>
              </td>
              <td class="py-3.5 pr-4 align-top whitespace-nowrap text-[#5f6368] text-xs">${escapeHTML(item.date)}</td>
              <td class="py-3.5 pr-4 align-top">${renderAssigneeBadge(item.owner)}</td>
              <td class="py-3.5 pr-4 align-top whitespace-nowrap">
                <select onchange="updateStatus('${item.id}', 'decisions', this.value)" class="px-2 py-1 bg-[#f0f4f9] hover:bg-[#e2e8f0] text-[#1f1f1f] text-xs font-medium rounded-lg cursor-pointer focus:outline-none focus:ring-1 focus:ring-[#0b57d0]">
                  <option value="Proposed" ${item.status === 'Proposed' ? 'selected' : ''}>Proposed</option>
                  <option value="Approved" ${item.status === 'Approved' ? 'selected' : ''}>Approved</option>
                  <option value="Rejected" ${item.status === 'Rejected' ? 'selected' : ''}>Rejected</option>
                </select>
              </td>
              <td class="py-3.5 align-top text-right whitespace-nowrap">
                <div class="flex items-center justify-end space-x-1">
                  <button onclick="openEditModal('${item.id}', 'decisions')" class="p-1.5 hover:bg-[#f0f4f9] rounded-md text-[#5f6368] hover:text-[#1f1f1f] transition" title="Edit">
                    <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                  </button>
                  <button onclick="deleteEntry('${item.id}', 'decisions')" class="p-1.5 hover:bg-[#fce8e6] rounded-md text-[#5f6368] hover:text-[#d93025] transition" title="Delete">
                    <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                  </button>
                </div>
              </td>
            `;
            tbody.appendChild(row);
          });
        }
      } else {
        document.getElementById('decisions-container').classList.add('hidden');
        document.getElementById('risks-container').classList.remove('hidden');
        document.getElementById('add-btn').innerHTML = '<span class="text-sm">+</span> <span>New Risk</span>';

        const tbody = document.getElementById('risks-tbody');
        tbody.innerHTML = '';

        const filteredRisks = state.risks.filter(r => {
          return r.title.toLowerCase().includes(query) ||
                 (r.mitigation && r.mitigation.toLowerCase().includes(query)) ||
                 r.owner.toLowerCase().includes(query) ||
                 r.status.toLowerCase().includes(query) ||
                 r.severity.toLowerCase().includes(query);
        });

        if (filteredRisks.length === 0) {
          tbody.innerHTML = `
            <tr>
              <td colspan="6" class="py-8 text-center text-[#5f6368] text-xs">No tracked risks found matching your criteria.</td>
            </tr>
          `;
        } else {
          filteredRisks.forEach(item => {
            let severityColorClass = "text-[#5f6368]";
            if (item.severity === 'High') {
              severityColorClass = "text-[#d93025] font-medium";
            } else if (item.severity === 'Medium') {
              severityColorClass = "text-[#b06000] font-medium";
            }

            const row = document.createElement('tr');
            row.className = "hover:bg-[#f8f9fa] transition";
            row.innerHTML = `
              <td class="py-3.5 pr-4 align-top">
                <div class="font-medium text-[#1f1f1f] text-sm">${escapeHTML(item.title)}</div>
              </td>
              <td class="py-3.5 pr-4 align-top">
                <div class="text-xs text-[#5f6368]">${escapeHTML(item.mitigation || '')}</div>
              </td>
              <td class="py-3.5 pr-4 align-top whitespace-nowrap text-xs ${severityColorClass}">${escapeHTML(item.severity)}</td>
              <td class="py-3.5 pr-4 align-top">${renderAssigneeBadge(item.owner)}</td>
              <td class="py-3.5 pr-4 align-top whitespace-nowrap">
                <select onchange="updateStatus('${item.id}', 'risks', this.value)" class="px-2 py-1 bg-[#f0f4f9] hover:bg-[#e2e8f0] text-[#1f1f1f] text-xs font-medium rounded-lg cursor-pointer focus:outline-none focus:ring-1 focus:ring-[#0b57d0]">
                  <option value="Active" ${item.status === 'Active' ? 'selected' : ''}>Active</option>
                  <option value="Mitigated" ${item.status === 'Mitigated' ? 'selected' : ''}>Mitigated</option>
                  <option value="Resolved" ${item.status === 'Resolved' ? 'selected' : ''}>Resolved</option>
                </select>
              </td>
              <td class="py-3.5 align-top text-right whitespace-nowrap">
                <div class="flex items-center justify-end space-x-1">
                  <button onclick="openEditModal('${item.id}', 'risks')" class="p-1.5 hover:bg-[#f0f4f9] rounded-md text-[#5f6368] hover:text-[#1f1f1f] transition" title="Edit">
                    <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                  </button>
                  <button onclick="deleteEntry('${item.id}', 'risks')" class="p-1.5 hover:bg-[#fce8e6] rounded-md text-[#5f6368] hover:text-[#d93025] transition" title="Delete">
                    <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                  </button>
                </div>
              </td>
            `;
            tbody.appendChild(row);
          });
        }
      }
    }

    // Switch between Decision and Risk modes
    function switchTab(tab) {
      activeTab = tab;

      const btnDecisions = document.getElementById('tab-decisions');
      const btnRisks = document.getElementById('tab-risks');

      if (tab === 'decisions') {
        btnDecisions.className = "px-4 py-1.5 text-xs font-medium rounded-md transition duration-150 ease-in-out bg-white text-[#1f1f1f] shadow-sm";
        btnRisks.className = "px-4 py-1.5 text-xs font-medium rounded-md transition duration-150 ease-in-out text-[#5f6368] hover:text-[#1f1f1f]";
      } else {
        btnDecisions.className = "px-4 py-1.5 text-xs font-medium rounded-md transition duration-150 ease-in-out text-[#5f6368] hover:text-[#1f1f1f]";
        btnRisks.className = "px-4 py-1.5 text-xs font-medium rounded-md transition duration-150 ease-in-out bg-white text-[#1f1f1f] shadow-sm";
      }

      render();
    }

    function handleSearch() {
      render();
    }

    // Populate the dropdown selector
    function populateOwnerSelect() {
      const select = document.getElementById('form-owner');
      select.innerHTML = teamMembers.map(m => `<option value="${m.name}">${m.name}</option>`).join('');
    }

    // Form Overlay Controllers
    function openAddModal() {
      isModalOpen = true;
      document.getElementById('form-id').value = '';
      document.getElementById('form-type').value = activeTab;

      document.getElementById('form-title').value = '';
      document.getElementById('form-notes').value = '';
      document.getElementById('form-mitigation').value = '';

      const today = new Date().toISOString().split('T')[0];
      document.getElementById('form-date').value = today;

      populateOwnerSelect();

      const statusSelect = document.getElementById('form-status');
      if (activeTab === 'decisions') {
        document.getElementById('modal-title').textContent = 'Log New Decision';
