    // Handle interactive submit
    function handleFormSubmit(event) {
      event.preventDefault();

      const id = document.getElementById('form-id').value;
      const type = document.getElementById('form-type').value;

      const title = document.getElementById('form-title').value.trim();
      const owner = document.getElementById('form-owner').value;
      const status = document.getElementById('form-status').value;

      if (type === 'decisions') {
        const date = document.getElementById('form-date').value;
        const notes = document.getElementById('form-notes').value.trim();

        if (id) {
          const index = state.decisions.findIndex(d => d.id === id);
          if (index !== -1) {
            state.decisions[index] = { ...state.decisions[index], title, owner, status, date, notes };
          }
        } else {
          const newId = 'dec-' + Date.now();
          state.decisions.push({ id: newId, title, owner, status, date, notes });
        }
      } else {
        const severity = document.getElementById('form-severity').value;
        const mitigation = document.getElementById('form-mitigation').value.trim();

        if (id) {
          const index = state.risks.findIndex(r => r.id === id);
          if (index !== -1) {
            state.risks[index] = { ...state.risks[index], title, owner, status, severity, mitigation };
          }
        } else {
          const newId = 'risk-' + Date.now();
          state.risks.push({ id: newId, title, owner, status, severity, mitigation });
        }
      }

      saveSyncedState(state);
      render();
      closeModal();
    }

    // Direct Status Update from table selects
    function updateStatus(id, type, newStatus) {
      if (type === 'decisions') {
        const index = state.decisions.findIndex(d => d.id === id);
        if (index !== -1) {
          state.decisions[index].status = newStatus;
        }
      } else {
        const index = state.risks.findIndex(r => r.id === id);
        if (index !== -1) {
          state.risks[index].status = newStatus;
        }
      }
      saveSyncedState(state);
    }

    // Delete Log Entry
    function deleteEntry(id, type) {
      if (!confirm('Are you sure you want to delete this log entry?')) return;

      if (type === 'decisions') {
        state.decisions = state.decisions.filter(d => d.id !== id);
      } else {
        state.risks = state.risks.filter(r => r.id !== id);
      }

      saveSyncedState(state);
      render();
    }

    // Multiplayer State Synchronization Pipeline
    async function loadSyncedState() {
      if (!envId) {
        // LocalStorage fallback for non-production / testing environments
        const local = localStorage.getItem(syncKey);
        if (local) {
          try {
            const parsed = JSON.parse(local);
            if (parsed && (parsed.decisions || parsed.risks)) {
              if (JSON.stringify(state) !== JSON.stringify(parsed)) {
                state = parsed;
                if (!isModalOpen) render();
              }
            }
          } catch (e) {
            console.error("Local storage error:", e);
          }
        }
        return;
      }

      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data) {
          if (JSON.stringify(state) !== JSON.stringify(json.data)) {
            state = json.data;
            if (!isModalOpen) {
              render();
            }
          }
        } else {
          saveSyncedState(defaultState);
        }
      } catch (err) {
        console.error("State syncer retrieve error:", err);
      }
    }

    async function saveSyncedState(newState) {
      state = newState;
      if (!envId) {
        localStorage.setItem(syncKey, JSON.stringify(newState));
        return;
      }
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
      } catch (err) {
        console.error("State syncer publish error:", err);
      }
    }

    // Bootstrap Pipeline
    window.addEventListener('DOMContentLoaded', () => {
      loadSyncedState();
      setInterval(loadSyncedState, 2000);
      render();
    });
  </script>
